function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: invalid input: ${str}`);
  }

  // Bare integer with no unit is milliseconds.
  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  const UNITS = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };
  // Match ms before m (longer units first).
  const SEGMENT = /^(\d+)(ms|s|m|h|d)/;

  let remaining = str;
  let total = 0;

  while (remaining.length > 0) {
    const match = SEGMENT.exec(remaining);
    if (!match) {
      throw new Error(`parseDuration: unparseable input: "${str}"`);
    }
    total += parseInt(match[1], 10) * UNITS[match[2]];
    remaining = remaining.slice(match[0].length);
  }

  return total;
}

